// ============================================================
// MERGE REPORT DATA - n8n Code Node
// ============================================================
// This node combines data from all Instantly API nodes and 
// prepares it for LLM report generation.
//
// INPUTS EXPECTED:
// - Get matched campaign data (campaign configuration)
// - Get Campaign Analytics (performance metrics)
// - Get all leads (lead records)
// - Get all accounts (sender accounts)
// - Workflow Configuration (request context)
//
// OUTPUT:
// - Single JSON object with all data structured for LLM
// ============================================================

// Get data from all input nodes
// IMPORTANT: Adjust these node names to match YOUR workflow's node names
const campaignData = $('Get matched campaign data').first().json;
const analyticsData = $('Get Campaign Analytics').first().json;
const leadsData = $('Get all leads').first().json;
const accountsData = $('Get all accounts').first().json;

// Get request context from upstream (passed through the workflow)
// IMPORTANT: Adjust 'Workflow Configuration' to match your node name
const requestContext = {
  clientName: $('Workflow Configuration').first().json.clientName,
  campaignName: $('Workflow Configuration').first().json.campaignName,
  startDate: $('Workflow Configuration').first().json.startDate,
  endDate: $('Workflow Configuration').first().json.endDate,
  platformName: $('Workflow Configuration').first().json.platformName,
  campaignContext: $('Workflow Configuration').first().json.campaignContext
};

// ============================================================
// PROCESS LEADS DATA
// ============================================================
const leads = leadsData.items || [];
const leadsAnalysis = {
  totalLeads: leads.length,
  byStatus: {},
  byJobTitle: {},
  byLocation: {},
  byCompany: {},
  withReplies: [],
  bounced: []
};

leads.forEach(lead => {
  // Count by status
  const status = lead.status;
  leadsAnalysis.byStatus[status] = (leadsAnalysis.byStatus[status] || 0) + 1;

  // Count by job title (from payload)
  const jobTitle = lead.payload?.jobTitle || 'Unknown';
  leadsAnalysis.byJobTitle[jobTitle] = (leadsAnalysis.byJobTitle[jobTitle] || 0) + 1;

  // Count by location - extract country/region
  const location = lead.payload?.location || 'Unknown';
  const locationParts = location.split(',');
  const region = locationParts[locationParts.length - 1]?.trim() || 'Unknown';
  leadsAnalysis.byLocation[region] = (leadsAnalysis.byLocation[region] || 0) + 1;

  // Count by company
  const company = lead.company_name || 'Unknown';
  leadsAnalysis.byCompany[company] = (leadsAnalysis.byCompany[company] || 0) + 1;

  // Track leads with replies
  if (lead.email_reply_count > 0) {
    leadsAnalysis.withReplies.push({
      email: lead.email,
      name: `${lead.first_name} ${lead.last_name}`,
      company: lead.company_name,
      jobTitle: lead.payload?.jobTitle,
      replyCount: lead.email_reply_count
    });
  }
});

// Sort and get top items
const topJobTitles = Object.entries(leadsAnalysis.byJobTitle)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 10)
  .map(([title, count]) => ({ 
    title, 
    count, 
    percentage: ((count / leads.length) * 100).toFixed(1) 
  }));

const topLocations = Object.entries(leadsAnalysis.byLocation)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 10)
  .map(([location, count]) => ({ 
    location, 
    count, 
    percentage: ((count / leads.length) * 100).toFixed(1) 
  }));

const topCompanies = Object.entries(leadsAnalysis.byCompany)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 10)
  .map(([company, count]) => ({ company, count }));

// ============================================================
// PROCESS ACCOUNTS DATA
// ============================================================
const accounts = accountsData.items || [];
const campaignEmailList = campaignData.email_list || [];

// Filter to only accounts used in this campaign
const campaignAccounts = accounts.filter(acc => 
  campaignEmailList.includes(acc.email)
);

const accountsAnalysis = {
  totalInCampaign: campaignAccounts.length,
  totalAvailable: accounts.length,
  averageWarmupScore: 0,
  byStatus: {},
  healthySenders: [],
  problemSenders: []
};

let warmupScoreSum = 0;
let warmupScoreCount = 0;

campaignAccounts.forEach(account => {
  // Track warmup scores
  if (account.stat_warmup_score !== undefined) {
    warmupScoreSum += account.stat_warmup_score;
    warmupScoreCount++;
  }

  // Categorize by status
  const status = account.status === 1 ? 'Active' : 'Inactive';
  accountsAnalysis.byStatus[status] = (accountsAnalysis.byStatus[status] || 0) + 1;

  // Track healthy vs problem senders
  const senderInfo = {
    email: account.email,
    name: `${account.first_name} ${account.last_name}`,
    warmupScore: account.stat_warmup_score || 0,
    status: account.status,
    trackingDomain: account.tracking_domain_name,
    trackingStatus: account.tracking_domain_status,
    dailyLimit: account.daily_limit
  };

  if (account.stat_warmup_score >= 80 && account.status === 1) {
    accountsAnalysis.healthySenders.push(senderInfo);
  } else {
    accountsAnalysis.problemSenders.push(senderInfo);
  }
});

accountsAnalysis.averageWarmupScore = warmupScoreCount > 0 
  ? Math.round(warmupScoreSum / warmupScoreCount) 
  : 0;

// ============================================================
// PROCESS CAMPAIGN CONFIGURATION
// ============================================================
const campaignConfig = {
  name: campaignData.name,
  id: campaignData.id,
  status: campaignData.status,
  statusText: ['Draft', 'Active', 'Paused', 'Completed'][campaignData.status] || 'Unknown',
  createdAt: campaignData.timestamp_created,
  updatedAt: campaignData.timestamp_updated,
  schedule: campaignData.campaign_schedule,
  sequences: campaignData.sequences,
  emailGap: campaignData.email_gap,
  dailyLimit: campaignData.daily_limit,
  senderCount: campaignData.email_list?.length || 0,
  openTracking: campaignData.open_tracking,
  linkTracking: campaignData.link_tracking,
  stopOnReply: campaignData.stop_on_reply,
  stopOnAutoReply: campaignData.stop_on_auto_reply
};

// Extract sequence steps for analysis
const sequenceSteps = [];
if (campaignData.sequences && campaignData.sequences[0]?.steps) {
  campaignData.sequences[0].steps.forEach((step, index) => {
    const variant = step.variants?.[0] || {};
    sequenceSteps.push({
      stepNumber: index + 1,
      type: step.type,
      delay: step.delay,
      subject: variant.subject || '(No subject / Reply thread)',
      body: variant.body || '',
      // Clean HTML from body for analysis
      bodyText: (variant.body || '')
        .replace(/<[^>]*>/g, ' ')
        .replace(/\s+/g, ' ')
        .trim()
    });
  });
}

// ============================================================
// CALCULATE DERIVED METRICS
// ============================================================
const analytics = analyticsData;
const calculatedMetrics = {
  replyRate: analytics.emails_sent_count > 0 
    ? ((analytics.reply_count_unique / analytics.emails_sent_count) * 100).toFixed(2) 
    : 0,
  bounceRate: analytics.emails_sent_count > 0 
    ? ((analytics.bounced_count / analytics.emails_sent_count) * 100).toFixed(2) 
    : 0,
  completionRate: analytics.leads_count > 0 
    ? ((analytics.completed_count / analytics.leads_count) * 100).toFixed(2) 
    : 0,
  autoReplyRate: analytics.emails_sent_count > 0 
    ? ((analytics.reply_count_automatic / analytics.emails_sent_count) * 100).toFixed(2) 
    : 0,
  emailsPerLead: analytics.leads_count > 0 
    ? (analytics.emails_sent_count / analytics.leads_count).toFixed(2) 
    : 0,
  humanReplies: analytics.reply_count_unique,
  autoReplies: analytics.reply_count_automatic
};

// ============================================================
// BUILD FINAL REPORT DATA OBJECT
// ============================================================
const reportData = {
  requestContext,
  campaignConfig,
  sequenceSteps,
  analytics: {
    ...analytics,
    calculated: calculatedMetrics
  },
  leadsAnalysis: {
    totalLeads: leadsAnalysis.totalLeads,
    topJobTitles,
    topLocations,
    topCompanies,
    leadsWithReplies: leadsAnalysis.withReplies
  },
  accountsAnalysis,
  // Metadata
  generatedAt: new Date().toISOString(),
  reportVersion: '1.0'
};

// ============================================================

// Extract human reply highlights from focused inbox
let replyHighlights = [];
try {
  const repliesRaw = $('Get Campaign Replies').first()?.json;
  const emails = Array.isArray(repliesRaw?.emails) ? repliesRaw.emails
    : Array.isArray(repliesRaw?.items) ? repliesRaw.items
    : Array.isArray(repliesRaw?.data) ? repliesRaw.data
    : [];
  // Filter to reporting window only
    const startTs = requestContext.startDate ? new Date(requestContext.startDate).getTime() : 0;
    const endTs = requestContext.endDate ? new Date(requestContext.endDate).getTime() + 86400000 : Infinity;
    const filtered = emails.filter(e => {
      const ts = new Date(e.timestamp_email || e.timestamp_created || e.created_at || 0).getTime();
      return ts >= startTs && ts <= endTs;
    });
    replyHighlights = filtered.map(e => ({
    from: e.from_address_email || e.from_address || e.from || '',
    subject: e.subject || '',
    body: (e.body?.text || e.body_text || e.text_body || e.snippet || '').slice(0, 1500),
    timestamp: e.timestamp || e.timestamp_created || e.created_at || ''
  }));
} catch(err) {
  replyHighlights = [];
}
reportData.replyHighlights = replyHighlights;

// RETURN OUTPUT
// ============================================================
return [{
  json: {
    reportData,
    // Stringified version for LLM prompt
    reportDataString: JSON.stringify(reportData, null, 2)
  }
}];

// n8n Code node (JavaScript)

// 1) Read the target campaign name from the form/input node
const form = $items("Workflow Configuration")?.[0]?.json ?? {};
const targetRaw =
  form.instantlyCampaignName ??
  form["Instantly Campaign Name"] ??
  "";


// 2) Read campaigns list from Instantly node output
// Your screenshot shows: { items: [ ...campaigns ] }
const campaigns =
  $json.items ??
  $json.data ??
  $json.campaigns ??
  [];

if (!targetRaw) {
  return [{
    json: {
      matched: false,
     reason: "No Instantly Campaign Name provided in 'Workflow Configuration' node.",

      availableCount: Array.isArray(campaigns) ? campaigns.length : null,
    }
  }];
}

if (!Array.isArray(campaigns)) {
  throw new Error(
    `Expected campaigns array but got: ${typeof campaigns}. ` +
    `Check previous node output shape (should have 'items: [...]').`
  );
}

// --- helpers ---
const norm = (s) =>
  (s ?? "")
    .toString()
    .toLowerCase()
    .replace(/\s+/g, " ")
    .trim();

const tokenize = (s) =>
  norm(s)
    .split(/[^a-z0-9]+/g)
    .filter(Boolean);

const scoreMatch = (name, target) => {
  const n = norm(name);
  const t = norm(target);

  if (n === t) return 100;
  if (n.includes(t)) return 90;
  if (t.includes(n)) return 80;

  const nt = new Set(tokenize(n));
  const tt = new Set(tokenize(t));
  const overlap = [...tt].filter(x => nt.has(x)).length;
  const denom = Math.max(1, tt.size);
  return Math.round((overlap / denom) * 70); // 0..70
};

// 3) Find best match
let best = null;
let bestScore = -1;

for (const c of campaigns) {
  const s = scoreMatch(c?.name, targetRaw);
  if (s > bestScore) {
    bestScore = s;
    best = c;
  }
}

// 4) Threshold (tune if needed)
const THRESHOLD = 85;

if (!best || bestScore < THRESHOLD) {
  return [{
    json: {
      matched: false,
      targetCampaignName: targetRaw,
      bestGuessName: best?.name ?? null,
      bestGuessScore: bestScore,
      availableCount: campaigns.length,
      // Helpful for debugging without dumping massive JSON
      availableNamesSample: campaigns.slice(0, 25).map(c => c?.name).filter(Boolean),
    }
  }];
}

// 5) Return matched campaign (and optionally merge form fields)
return [{
  json: {
    // keep your original request context if you want downstream nodes to use it
    ...form,

    matched: true,
    targetCampaignName: targetRaw,
    matchedCampaignId: best.id,
    matchedCampaignName: best.name,
    matchedCampaignStatus: best.status,

    // full object in case you need sequences/schedule later
    matchedCampaign: best,

    matchScore: bestScore,
  }
}];

// ============================================================
// HEYREACH CAMPAIGN NAME MATCH - n8n Code Node
// ============================================================
// Node Name: "Match Heyreach Campaign Name - Exist or not"
// Purpose: Check if user's input campaign name exists in HeyReach
// Input: Output from "Retrieve all campaigns" node
// ============================================================

// Get the campaign name from user input (Workflow Configuration)
const config = $('Workflow Configuration').first().json;
const inputCampaignName = (
  config.heyreachCampaignName ||
  config.HeyReachCampaignName ||
  config["HeyReach Campaign Name"] ||
  ""
).toLowerCase().trim();

// Get all campaigns from HeyReach API response
// Response structure: [{ totalCount: number, items: [...campaigns] }]
const apiResponse = $input.first().json;

// Handle the nested structure - campaigns are in items array
let campaigns = [];
if (apiResponse.items && Array.isArray(apiResponse.items)) {
  campaigns = apiResponse.items;
} else if (Array.isArray(apiResponse) && apiResponse[0]?.items && Array.isArray(apiResponse[0].items)) {
  campaigns = apiResponse[0].items;
} else if (Array.isArray(apiResponse)) {
  campaigns = apiResponse;
}


// Search for matching campaign (case-insensitive)
const matchedCampaign = campaigns.find(campaign => {
   const campaignName = (campaign.name || '').toLowerCase().trim();
  return campaignName === inputCampaignName;
});

// If found, return campaign details for downstream nodes
if (matchedCampaign) {
  return [{
    json: {
      matched: true,
      campaignId: matchedCampaign.id,
      heyreachcampaignName: matchedCampaign.name,
      campaignStatus: matchedCampaign.status,
      campaignAccountIds: matchedCampaign.campaignAccountIds || [],
      linkedInUserListId: matchedCampaign.linkedInUserListId,
      linkedInUserListName: matchedCampaign.linkedInUserListName,
      progressStats: matchedCampaign.progressStats,
      creationTime: matchedCampaign.creationTime,

      // Pass through original config
      clientName: config.clientName,
      platformName: config.platformName,
      startDate: config.startDate,
      endDate: config.endDate,

      // Additional context
      totalCampaignsAvailable: campaigns.length
    }
  }];
} else {
  // Campaign not found - return error info
  const availableCampaignNames = campaigns
    .map(c => c.name)
    .filter(name => name)
    .slice(0, 15);

  return [{
    json: {
      matched: false,
      error: `Campaign "${config.heyreachCampaignName}" not found in HeyReach`,
      searchedFor: config.heyreachCampaignName,
      availableCampaigns: availableCampaignNames,
      totalCampaigns: campaigns.length,
      suggestion: "Check the campaign name spelling or choose from available campaigns above",

      clientName: config.clientName,
      platformName: config.platformName,
      startDate: config.startDate,
      endDate: config.endDate
    }
  }];
}

// ============================================================
// HEYREACH MERGE REPORT DATA - Based on Actual API Responses
// ============================================================
// Node Name: "Merge Heyreach Nodes Data"
// Inputs: 4 HeyReach API nodes after campaign match
// ============================================================

// Get request context from match node
const matchData = $('Match Heyreach Campaign Name - Exist or not').first().json;

const requestContext = {
  clientName: matchData.clientName || 'Unknown Client',
  campaignName: matchData.campaignName,
  campaignId: matchData.campaignId,
  startDate: matchData.startDate,
  endDate: matchData.endDate,
  platformName: 'HeyReach',
  campaignContext: $('Workflow Configuration').first().json.campaignContext
};

// ============================================================
// 1. CAMPAIGN DATA - from "Retrieve found campaign data"
// Structure: [{ id, name, status, progressStats, campaignAccountIds, ... }]
// ============================================================
let campaignData = {};
try {
  const rawCampaign = $('Retrieve found campaign data').first().json;
  campaignData = rawCampaign;
} catch (e) {
  console.log('Campaign data error:', e.message);
  campaignData = matchData; // fallback to match data
}

// ============================================================
// 2. STATISTICS - from "Retrieve overall statistics for found campaign"
// Structure: [{ byDayStats: {...}, overallStats: {...} }]
// ============================================================
let statsData = { overallStats: {}, byDayStats: {} };
try {
  const rawStats = $('Retrieve overall statistics for found campaign').first().json;
  statsData = rawStats;
} catch (e) {
  console.log('Stats data error:', e.message);
}

// ============================================================
// 3. LINKEDIN ACCOUNTS - from "Retrieve all LinkedIn accounts"
// Structure: [{ totalCount, items: [{id, firstName, lastName, isActive, ...}] }]
// ============================================================
let accountsData = [];
try {
  const rawAccounts = $('Retrieve all LinkedIn accounts').first().json;
  if (rawAccounts.items) {
    accountsData = rawAccounts.items;
  } else if (Array.isArray(rawAccounts)) {
    accountsData = rawAccounts;
  }
} catch (e) {
  console.log('Accounts data error:', e.message);
}

// ============================================================
// 4. INBOX MESSAGES - from "Retrieve inbox messages for found campaign"
// Structure: [{ totalCount, items: [{id, lastMessageText, lastMessageSender, 
//              correspondentProfile, messages: [...], ...}] }]
// ============================================================
let inboxData = [];
try {
  const rawInbox = $('Retrieve inbox messages for found campaign').first().json;
  if (rawInbox.items) {
    inboxData = rawInbox.items;
  } else if (Array.isArray(rawInbox)) {
    inboxData = rawInbox;
  }
} catch (e) {
  console.log('Inbox data error:', e.message);
}

// ============================================================
// PROCESS CAMPAIGN CONFIG
// ============================================================

const campaignConfig = {
  id: campaignData.id || matchData.campaignId,
  name: campaignData.name || matchData.campaignName,
  status: campaignData.status || 'Unknown',
  creationTime: campaignData.creationTime,
  linkedInUserListName: campaignData.linkedInUserListName,
  linkedInUserListId: campaignData.linkedInUserListId,
  senderAccountIds: campaignData.campaignAccountIds || [],
  senderCount: (campaignData.campaignAccountIds || []).length,

  // Progress stats from campaign data
  progressStats: campaignData.progressStats || {
    totalUsers: 0,
    totalUsersInProgress: 0,
    totalUsersPending: 0,
    totalUsersFinished: 0,
    totalUsersFailed: 0,
    totalUsersManuallyStopped: 0,
    totalUsersExcluded: 0
  },

  // Settings
  excludeInOtherCampaigns: campaignData.excludeInOtherCampaigns || false,
  excludeHasOtherAccConversations: campaignData.excludeHasOtherAccConversations || false
};

// ============================================================
// PROCESS OVERALL STATISTICS
// ============================================================

const overallStats = statsData.overallStats || {};

const analytics = {
  // Raw metrics from API
  connectionsSent: overallStats.connectionsSent || 0,
  connectionsAccepted: overallStats.connectionsAccepted || 0,
  profileViews: overallStats.profileViews || 0,
  messagesSent: overallStats.messagesSent || 0,
  totalMessageStarted: overallStats.totalMessageStarted || 0,
  totalMessageReplies: overallStats.totalMessageReplies || 0,
  inmailMessagesSent: overallStats.inmailMessagesSent || 0,
  totalInmailStarted: overallStats.totalInmailStarted || 0,
  totalInmailReplies: overallStats.totalInmailReplies || 0,
  postLikes: overallStats.postLikes || 0,
  follows: overallStats.follows || 0,

  // Pre-calculated rates from API (as decimals, need to convert to %)
  connectionAcceptanceRate: overallStats.connectionAcceptanceRate 
    ? (overallStats.connectionAcceptanceRate * 100).toFixed(2) 
    : '0.00',
  messageReplyRate: overallStats.messageReplyRate 
    ? (overallStats.messageReplyRate * 100).toFixed(2) 
    : '0.00',
  inMailReplyRate: overallStats.inMailReplyRate 
    ? (overallStats.inMailReplyRate * 100).toFixed(2) 
    : '0.00',

  // Progress stats
  totalLeads: campaignConfig.progressStats.totalUsers,
  leadsFinished: campaignConfig.progressStats.totalUsersFinished,
  leadsFailed: campaignConfig.progressStats.totalUsersFailed,
  leadsInProgress: campaignConfig.progressStats.totalUsersInProgress,
  leadsPending: campaignConfig.progressStats.totalUsersPending,
  leadsExcluded: campaignConfig.progressStats.totalUsersExcluded,

  // Calculated metrics
  completionRate: campaignConfig.progressStats.totalUsers > 0
    ? ((campaignConfig.progressStats.totalUsersFinished / campaignConfig.progressStats.totalUsers) * 100).toFixed(2)
    : '0.00',
  failureRate: campaignConfig.progressStats.totalUsers > 0
    ? ((campaignConfig.progressStats.totalUsersFailed / campaignConfig.progressStats.totalUsers) * 100).toFixed(2)
    : '0.00'
};

// ============================================================
// PROCESS DAILY STATISTICS (for trends)
// ============================================================

const byDayStats = statsData.byDayStats || {};
const dailyTrends = [];

Object.keys(byDayStats).sort().forEach(date => {
  const dayData = byDayStats[date];
  // Only include days with activity
  if (dayData.connectionsSent > 0 || dayData.connectionsAccepted > 0 || 
      dayData.totalMessageStarted > 0 || dayData.totalMessageReplies > 0) {
    dailyTrends.push({
      date: date.split('T')[0], // Just the date part
      connectionsSent: dayData.connectionsSent,
      connectionsAccepted: dayData.connectionsAccepted,
      messagesStarted: dayData.totalMessageStarted,
      replies: dayData.totalMessageReplies,
      profileViews: dayData.profileViews,
      connectionAcceptanceRate: dayData.connectionAcceptanceRate 
        ? (dayData.connectionAcceptanceRate * 100).toFixed(1) + '%'
        : '0%'
    });
  }
});

// ============================================================
// PROCESS LINKEDIN ACCOUNTS (filter to campaign senders)
// ============================================================

const campaignAccountIds = campaignConfig.senderAccountIds;

const accountsAnalysis = {
  totalAccountsInCampaign: campaignAccountIds.length,
  accounts: [],
  activeCount: 0,
  healthyCount: 0,
  warningCount: 0
};

accountsData.forEach(account => {
  // Only include accounts used in this campaign
  if (campaignAccountIds.includes(account.id)) {
    const isActive = account.isActive === true;
    const isHealthy = account.authIsValid === true;

    if (isActive) accountsAnalysis.activeCount++;
    if (isHealthy) accountsAnalysis.healthyCount++;
    else accountsAnalysis.warningCount++;

    accountsAnalysis.accounts.push({
      id: account.id,
      name: `${account.firstName || ''} ${account.lastName || ''}`.trim(),
      email: account.emailAddress,
      profileUrl: account.profileUrl,
      isActive: isActive,
      authIsValid: account.authIsValid,
      activeCampaigns: account.activeCampaigns || 0,
      hasNavigator: account.isValidNavigator || false,
      hasRecruiter: account.isValidRecruiter || false,
      status: isHealthy ? (isActive ? 'Active' : 'Inactive') : 'Auth Issue'
    });
  }
});

// ============================================================
// PROCESS INBOX MESSAGES - Extract replies and analyze sentiment
// ============================================================

const replyAnalysis = {
  totalConversations: inboxData.length,
  conversationsWithReplies: 0,
  totalReplies: 0,
  replies: [],
  sentimentBreakdown: {
    positive: [],
    neutral: [],
    negative: [],
    informational: []
  },
  messageTemplate: null // Will capture the sent message template
};

// Sentiment keywords
const sentimentKeywords = {
  positive: [
    'interested', 'yes', 'sure', 'love to', 'sounds good', 'let\'s connect',
    'happy to', 'schedule', 'call', 'meeting', 'tell me more', 'send more',
    'great', 'perfect', 'excited', 'looking forward', 'thanks for reaching',
    'keep me posted', 'next one'
  ],
  negative: [
    'not interested', 'no thanks', 'no thank you', 'remove', 'stop',
    'don\'t contact', 'unsubscribe', 'spam', 'wrong person', 'don\'t do',
    'not relevant', 'not a fit', 'pass'
  ],
  neutral: [
    'not now', 'bad timing', 'busy', 'maybe later', 'check back',
    'not the right time', 'reach out later', 'next quarter', 'missed'
  ]
};

function classifySentiment(text) {
  if (!text) return 'informational';
  const lowerText = text.toLowerCase();

  for (const keyword of sentimentKeywords.positive) {
    if (lowerText.includes(keyword)) return 'positive';
  }
  for (const keyword of sentimentKeywords.negative) {
    if (lowerText.includes(keyword)) return 'negative';
  }
  for (const keyword of sentimentKeywords.neutral) {
    if (lowerText.includes(keyword)) return 'neutral';
  }
  return 'informational';
}

// Lead analysis from inbox data
const leadsAnalysis = {
  totalLeads: analytics.totalLeads,
  byJobTitle: {},
  byCompany: {},
  byLocation: {},
  connectedLeads: [],
  repliedLeads: []
};

// Process each conversation
inboxData.forEach(conversation => {
  const profile = conversation.correspondentProfile || {};
  const messages = conversation.messages || [];

  // Extract lead info
  const leadInfo = {
    name: `${profile.firstName || ''} ${profile.lastName || ''}`.trim(),
    firstName: profile.firstName,
    lastName: profile.lastName,
    headline: profile.headline || '',
    company: profile.companyName || '',
    position: profile.position || profile.headline || '',
    location: profile.location || '',
    email: profile.emailAddress || profile.customEmailAddress || '',
    linkedInUrl: profile.profileUrl || '',
    customFields: profile.customFields || []
  };

  // Aggregate by job title/headline
  if (leadInfo.headline) {
    leadsAnalysis.byJobTitle[leadInfo.headline] = (leadsAnalysis.byJobTitle[leadInfo.headline] || 0) + 1;
  }

  // Aggregate by company
  if (leadInfo.company) {
    leadsAnalysis.byCompany[leadInfo.company] = (leadsAnalysis.byCompany[leadInfo.company] || 0) + 1;
  }

  // Aggregate by location
  if (leadInfo.location) {
    leadsAnalysis.byLocation[leadInfo.location] = (leadsAnalysis.byLocation[leadInfo.location] || 0) + 1;
  }

  // Capture message template from first sent message (ME)
  if (!replyAnalysis.messageTemplate) {
    const sentMessage = messages.find(m => m.sender === 'ME');
    if (sentMessage) {
      replyAnalysis.messageTemplate = {
        body: sentMessage.body,
        isInMail: sentMessage.isInMail || false
      };
    }
  }

  // Find replies (messages from CORRESPONDENT)
  const correspondentReplies = messages.filter(m => m.sender === 'CORRESPONDENT');

  if (correspondentReplies.length > 0) {
    replyAnalysis.conversationsWithReplies++;
    replyAnalysis.totalReplies += correspondentReplies.length;

    // Process each reply
    // Filter replies to reporting window only
    const startTs = requestContext.startDate ? new Date(requestContext.startDate).getTime() : 0;
    const endTs = requestContext.endDate ? new Date(requestContext.endDate).getTime() + 86400000 : Infinity;
    const windowReplies = correspondentReplies.filter(m => {
      const ts = new Date(m.createdAt || m.timestamp || 0).getTime();
      return ts >= startTs && ts <= endTs;
    });
    windowReplies.forEach(reply => {
      const replyText = reply.body || '';
      const sentiment = classifySentiment(replyText);

      const replyRecord = {
        from: leadInfo.name,
        company: leadInfo.company,
        position: leadInfo.position,
        location: leadInfo.location,
        linkedInUrl: leadInfo.linkedInUrl,
        replyText: replyText,
        replyPreview: replyText.length > 150 ? replyText.substring(0, 150) + '...' : replyText,
        timestamp: reply.createdAt,
        sentiment: sentiment
      };

      replyAnalysis.replies.push(replyRecord);
      leadsAnalysis.repliedLeads.push(leadInfo);

      // Categorize by sentiment
      switch(sentiment) {
        case 'positive':
          replyAnalysis.sentimentBreakdown.positive.push(replyRecord);
          break;
        case 'negative':
          replyAnalysis.sentimentBreakdown.negative.push(replyRecord);
          break;
        case 'neutral':
          replyAnalysis.sentimentBreakdown.neutral.push(replyRecord);
          break;
        default:
          replyAnalysis.sentimentBreakdown.informational.push(replyRecord);
      }
    });
  }

  // Track connected leads (those who have conversations)
  leadsAnalysis.connectedLeads.push(leadInfo);
});

// Calculate sentiment summary
const totalRepliesForSentiment = replyAnalysis.totalReplies || 1;
replyAnalysis.sentimentSummary = {
  positive: {
    count: replyAnalysis.sentimentBreakdown.positive.length,
    percentage: ((replyAnalysis.sentimentBreakdown.positive.length / totalRepliesForSentiment) * 100).toFixed(1)
  },
  neutral: {
    count: replyAnalysis.sentimentBreakdown.neutral.length,
    percentage: ((replyAnalysis.sentimentBreakdown.neutral.length / totalRepliesForSentiment) * 100).toFixed(1)
  },
  negative: {
    count: replyAnalysis.sentimentBreakdown.negative.length,
    percentage: ((replyAnalysis.sentimentBreakdown.negative.length / totalRepliesForSentiment) * 100).toFixed(1)
  },
  informational: {
    count: replyAnalysis.sentimentBreakdown.informational.length,
    percentage: ((replyAnalysis.sentimentBreakdown.informational.length / totalRepliesForSentiment) * 100).toFixed(1)
  }
};

// Sort and get top items for leads analysis
const topJobTitles = Object.entries(leadsAnalysis.byJobTitle)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 10)
  .map(([title, count]) => ({
    title,
    count,
    percentage: ((count / Math.max(leadsAnalysis.connectedLeads.length, 1)) * 100).toFixed(1)
  }));

const topCompanies = Object.entries(leadsAnalysis.byCompany)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 10)
  .map(([company, count]) => ({ company, count }));

const topLocations = Object.entries(leadsAnalysis.byLocation)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 10)
  .map(([location, count]) => ({
    location,
    count,
    percentage: ((count / Math.max(leadsAnalysis.connectedLeads.length, 1)) * 100).toFixed(1)
  }));

// ============================================================
// BUILD FINAL REPORT DATA OBJECT
// ============================================================

const reportData = {
  requestContext,
  platformType: 'linkedin',

  campaignConfig,

  // Message sequence (from captured template)
  messageSequence: replyAnalysis.messageTemplate ? [{
    stepNumber: 1,
    type: replyAnalysis.messageTemplate.isInMail ? 'inmail' : 'message',
    action: 'LinkedIn Message',
    message: replyAnalysis.messageTemplate.body,
    delay: 0
  }] : [],

  analytics,
  dailyTrends,

  leadsAnalysis: {
    totalLeads: leadsAnalysis.totalLeads,
    connectedCount: leadsAnalysis.connectedLeads.length,
    repliedCount: leadsAnalysis.repliedLeads.length,
    topJobTitles,
    topCompanies,
    topLocations,
    connectedLeads: leadsAnalysis.connectedLeads.slice(0, 20), // Limit for report
    repliedLeads: leadsAnalysis.repliedLeads
  },

  replyAnalysis,
  accountsAnalysis,

  generatedAt: new Date().toISOString(),
  reportVersion: '2.0'
};

// ============================================================
// RETURN OUTPUT
// ============================================================

return [{
  json: {
    reportData,
    reportDataString: JSON.stringify(reportData, null, 2)
  }
}];

