// Get all input items
const items = $input.all();

// Merge all items into one object
let merged = {};
for (const item of items) {
  merged = { ...merged, ...item.json };
}

const clientName = merged.clientName || "Unknown Client";
const instantlyCampaignName = merged.instantlyCampaignName || "";
const heyreachCampaignName = merged.heyreachCampaignName || "";
const startDate = merged.startDate || "";
const endDate = merged.endDate || "";
const campaignContext = merged.campaignContext || "";

const instantlyText = merged.InstantlyText || merged.instantlyText || "";
const heyreachText = merged.heyreachText || merged.HeyreachText || "";

const instantlyLifetimeRaw = merged.instantlyLifetimeData || "";
const heyreachLifetimeRaw = merged.heyreachLifetimeData || "";

const INSTANTLY_FIELDS = [
  'campaign_name','leads_count','contacted_count','emails_sent_count',
  'open_count','open_count_unique','reply_count','reply_count_unique','bounced_count'
];

const HEYREACH_FIELDS = [
  'profileViews','postLikes','messagesSent','totalMessageReplies',
  'connectionsSent','connectionsAccepted','messageReplyRate','connectionAcceptanceRate'
];

const formatLifetime = (raw, label, allowedFields) => {
  if (!raw) return `*No ${label} lifetime data available.*`;
  try {
    const data = typeof raw === 'string' ? JSON.parse(raw) : raw;
    // Drill into overallStats if present (HeyReach), otherwise use top-level (Instantly)
    const target = data.overallStats || data;
    const lines = allowedFields
      .filter(k => target[k] !== null && target[k] !== undefined)
      .map(k => `- **${k}:** ${target[k]}`);
    return lines.length > 0 ? lines.join('\n') : `*No metrics available for ${label}.*`;
  } catch(e) {
    return String(raw);
  }
};

const headerLines = [
  `# Combined Outbound Report`,
  ``,
  `**Client:** ${clientName}`,
  `**Date Range:** ${startDate} to ${endDate}`,
  `**Instantly Campaign:** ${instantlyCampaignName}`,
  `**HeyReach Campaign:** ${heyreachCampaignName}`,
];
if (campaignContext) {
  headerLines.push(`**Campaign Context:** ${campaignContext}`);
}

const combined = [
  ...headerLines,
  ``,
  `---`,
  ``,
  `## Instantly (Email)`,
  instantlyText || "(No Instantly report text found.)",
  ``,
  `---`,
  ``,
  `## HeyReach (LinkedIn)`,
  heyreachText || "(No HeyReach report text found.)",
  ``,
  `---`,
  ``,
  `## Appendix: Lifetime Campaign Data`,
  ``,
  `### Instantly — Lifetime Analytics`,
  formatLifetime(instantlyLifetimeRaw, 'Instantly', INSTANTLY_FIELDS),
  ``,
  `### HeyReach — Lifetime Analytics`,
  formatLifetime(heyreachLifetimeRaw, 'HeyReach', HEYREACH_FIELDS),
].join("\n");

return [{ json: {
  clientName,
  instantlyCampaignName,
  heyreachCampaignName,
  startDate,
  endDate,
  campaignContext,
  output: combined
}}];

